VALUES
  ('cpa-moex-01435', 'cpa', 'cpa-moex-102-78566e18', 'sub-cpa-01', NULL, 'single_choice', '甲公司從事手機觸控面板開發的研究，20X5 年初簽訂研究計畫專案經費為$300,000，期間三年，各 年度估計完工尚須投入成本無法可靠估計，但20X5年底預期所有已投入成本皆可回收，20X6年可 合理預期已發生成本在$160,000的額度內可回收，20X7年完成研究計畫並確定全部委託經費均可回 收。各年相關資料如下： 20X5年 20X6年 20X7年 每年年底累計實際研究成本 $80,000 $180,000 $270,000 估計完工尚須投入成本 無法可靠估計 無法可靠估計 0 完工百分比 無法可靠估計 無法可靠估計 100% 若公司交易結果無法可靠估計，則在公司採「成本回收法」下，各年度應認列的勞務(損)益為何？ 20X5年 20X6年 20X7年', '["$1,000 $16,000 $14,000", "0 (20,000) 50,000", "0 (15,000) 45,000", "(1,000) 20,000 20,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "6d4bb59e61f3", "answer_pdf_sha1": "ad30222b6792", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01436', 'cpa', 'cpa-moex-102-78566e18', 'sub-cpa-01', NULL, 'single_choice', '下列與繼續經營假設有關的說明，何者正確？', '["評估時，應考量未來至少一個營業週期以上所有可得資訊", "若企業有營運獲利的歷史且可供取得其需要之財務資源，仍需再蒐集額外資訊", "若未依據繼續經營假設編製財務報表，則應揭露此事實，並說明編製財務報表的基礎與解釋不被 視為繼續經營企業的理由", "必須評估預計的債務清償時程以及借新還舊資金的潛在來源"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "6d4bb59e61f3", "answer_pdf_sha1": "ad30222b6792", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01437', 'cpa', 'cpa-moex-102-78566e18', 'sub-cpa-01', NULL, 'single_choice', '阿宗商號 20X1 年按權責基礎認列銷貨收入$650,000，20X1 年初之應收帳款與備抵壞帳餘額分別為 $155,000 與$12,000，20X1 年中曾沖銷帳款$7,000，20X1 年底之應收帳款與備抵壞帳餘額分別為 $215,000與$20,600。試問阿宗商號按現金基礎所認列之銷貨收入為何？', '["$583,000", "$590,000", "$598,600", "$605,600"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "6d4bb59e61f3", "answer_pdf_sha1": "ad30222b6792", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01438', 'cpa', 'cpa-moex-102-78566e18', 'sub-cpa-01', NULL, 'single_choice', '甲公司在20X1年12月31日帳上機器原始成本為$800,000，累計折舊為$300,000，其剩餘的耐用年 限為10年且無殘值。甲公司於20X2年1月1日決定從成本模式轉為重估價模式作為續後評價，假 設該機器當日之公允價值為$900,000，且甲公司決定在重估價日依資產帳面金額之變動，按比例重新 計算累計折舊。則甲公司20X2年1月1日重估價後，該機器的累計折舊金額為何？', '["$540,000", "$300,000", "$0", "$480,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "6d4bb59e61f3", "answer_pdf_sha1": "ad30222b6792", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01439', 'cpa', 'cpa-moex-102-78566e18', 'sub-cpa-01', NULL, 'single_choice', '單獨取得無形資產之成本不包括下列何項？', '["購買價格，包含相關稅捐", "直接使資產達到可供使用狀態所支付員工之勞務成本", "直接使資產達到可供使用狀態所支付員工之專業服務費", "使用或重新配置無形資產所產生之成本"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "6d4bb59e61f3", "answer_pdf_sha1": "ad30222b6792", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01440', 'cpa', 'cpa-moex-102-78566e18', 'sub-cpa-01', NULL, 'single_choice', '甲公司接受政府補助款購買公允價值$1,000,000之儀器設備一台，估計耐用年限10年，無殘值。甲 公司對於此項補助之分錄為何？', '["借記：不動產、廠房及設備1,000,000；貸記：營業外收入1,000,000", "借記：不動產、廠房及設備1,000,000；貸記：遞延收益1,000,000", "借記：不動產、廠房及設備1,000,000；貸記：營業外支出1,000,000", "不作分錄"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "6d4bb59e61f3", "answer_pdf_sha1": "ad30222b6792", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01441', 'cpa', 'cpa-moex-102-78566e18', 'sub-cpa-01', NULL, 'single_choice', '理霖公司於20X1年以2,500萬元取得一土地。此土地於20X2年可回收金額為2,000萬元。假設理霖 公司於 20X3 年決定將該土地的評價從成本模式轉為重估價模式，該土地於 20X3 年底公允價值為 2,800萬元，則理霖公司於20X3年可認列重估增值金額為何？', '["300萬元", "800萬元", "500萬元", "0元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "6d4bb59e61f3", "answer_pdf_sha1": "ad30222b6792", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01442', 'cpa', 'cpa-moex-102-78566e18', 'sub-cpa-01', NULL, 'single_choice', '復興公司X1年初採吸收合併方式以130億元買入八德公司全部股份，並認列八德公司所有不含商譽 之淨資產（公允價值）100億元。適用之營利事業所得稅稅率為25%。已知復興公司申報所得稅時， 商譽按五年攤折，X1年底經評估該商譽沒有減損。復興公司下列有關商譽之遞延所得稅會計處理， 何者正確？', '["X1年初合併時應認列遞延所得稅負債10億元", "X1年初合併時應認列遞延所得稅負債7.5億元", "X1年底應認列遞延所得稅負債1.5億元", "X1年底應認列遞延所得稅負債為0元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "6d4bb59e61f3", "answer_pdf_sha1": "ad30222b6792", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01443', 'cpa', 'cpa-moex-102-78566e18', 'sub-cpa-01', NULL, 'single_choice', '甲公司計畫處分某一子公司，作為一項待出售資產。此子公司分類為待出售前再衡量之帳面金額為 400萬元（包含商譽30萬元；固定資產以成本列報160萬元；固定資產以重估價金額列報80萬元； 存貨60萬元；備供出售金融資產70萬元）。假設甲公司估計此子公司之公允價值減出售成本之金額 為220萬元。則分攤至固定資產合計應列報之減損金額為多少？', '["150萬元", "122萬元", "115萬元", "100萬元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "6d4bb59e61f3", "answer_pdf_sha1": "ad30222b6792", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01444', 'cpa', 'cpa-moex-102-78566e18', 'sub-cpa-01', NULL, 'single_choice', '甲公司於20X1年12月31日以$35,000,000取得乙公司30%股權，20X2年乙公司淨利為$700,000， 且支付現金股利$350,000，20X2年12月31日該投資公允價值為$36,000,000，假若甲公司將該筆採 權益法之長期股權投資錯誤記錄為以公允價值衡量之金融資產，則對20X2年底之投資帳面金額、稅 後淨利與投資活動現金流量有何影響？', '["低估、低估、低估", "低估、低估、無影響", "高估、高估、高估", "高估、高估、無影響"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "6d4bb59e61f3", "answer_pdf_sha1": "ad30222b6792", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01445', 'cpa', 'cpa-moex-102-78566e18', 'sub-cpa-01', NULL, 'single_choice', '甲公司於20X1年2月1日以面額買入乙公司附可分離認股權公司債20張（每張面額$100,000，票 面利率為2%，每張附1,000單位認股權，每單位認股權有權利以$20認購乙公司普通股1股，每單 位認股權公允價值為$4）。甲公司另支付0.3%之手續費。甲公司將公司債分類為以攤銷後成本衡量， 認股權則分類為以公允價值衡量。下列何者為甲公司於20X1年2月1日之會計分錄？', '["金融資產－以公允價值衡量（認股權） 80,000 金融資產－以攤銷後成本衡量（債券） 1,925,760 手續費 240 現金 2,006,000", "金融資產－以公允價值衡量（認股權） 80,000 金融資產－以攤銷後成本衡量（債券） 1,926,000 現金 2,006,000", "金融資產－以公允價值衡量（附認股權公司債） 2,000,000 手續費 6,000 現金 2,006,000", "金融資產－以攤銷後成本衡量（債券） 2,006,000 現金 2,006,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "6d4bb59e61f3", "answer_pdf_sha1": "ad30222b6792", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01446', 'cpa', 'cpa-moex-102-78566e18', 'sub-cpa-01', NULL, 'single_choice', '甲公司於20X1年5月1日以每股$36買入乙公司普通股10,000股，甲公司對該股票投資以公允價值 衡量金融資產認列。20X1年8月20日甲公司收到乙公司每股$3.2現金股利，20X1年12月31日乙 公司每股市價為$45。則20X1年12月31日甲公司對該投資之金融資產公允價值變動利益為：', '["$32,000", "$58,000", "$90,000", "$112,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "6d4bb59e61f3", "answer_pdf_sha1": "ad30222b6792", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01447', 'cpa', 'cpa-moex-102-78566e18', 'sub-cpa-01', NULL, 'single_choice', '甲公司於20X1年1月1日以$98,119買入一張面額$100,000乙公司公司債，票面利率4%，每年6月 30日與12月31日付息，於20X2年12月31日到期，有效利率為5%，甲公司對此債券投資以攤銷 後成本衡量認列。若甲公司於20X2年9月30日，以$99,700加計應收利息出售，另支付$200手續 費，則此債券投資之處分損益為何？', '["處分損失$256", "處分損失$56", "處分利益$256", "處分利益$56"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "6d4bb59e61f3", "answer_pdf_sha1": "ad30222b6792", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01448', 'cpa', 'cpa-moex-102-78566e18', 'sub-cpa-01', NULL, 'single_choice', '臺北公司於第一年初給與50位員工各100單位之認股權，該給與之條件係員工必須繼續服務3年。 臺北公司估計每一認股權之公允價值為$30。第一年底，有2位員工離職，臺北公司估計至第三年年 底共有10位員工離職。第二年底，有3位員工離職，在考慮可能離職率後，臺北公司仍估計至第三 年年底共有10位員工離職，未能取得其認股權。則臺北公司第二年認列之薪資費用為若干？', '["$0", "$40,000", "$47,000", "$50,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "6d4bb59e61f3", "answer_pdf_sha1": "ad30222b6792", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01449', 'cpa', 'cpa-moex-102-78566e18', 'sub-cpa-01', NULL, 'single_choice', '在合併報表中，下列何者屬於股東權益組成項目？①應分配股票股利 ②非控制權益', '["僅", "屬於股東權益組成項目", "僅", "屬於股東權益組成項目"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "6d4bb59e61f3", "answer_pdf_sha1": "ad30222b6792", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01450', 'cpa', 'cpa-moex-102-78566e18', 'sub-cpa-01', NULL, 'single_choice', '花蓮公司100年度之淨利為$7,500,000，其中，繼續營業部門淨利為$6,000,000。其他相關資料如 下：100年1月1日普通股流通在外股數300,000股；5月1日現金增資150,000股；6月1日配 發100%之股票股利；11月1日買回庫藏股90,000股。公司無任何稀釋性潛在普通股存在。花 蓮公司目前正編製公司 100年度損益表相關資料，試問計算每股盈餘時之普通股加權平均流通 在外股數為多少股？', '["625,000", "680,000", "725,000", "785,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:15+00:00", "source_pdf_sha1": "6d4bb59e61f3", "answer_pdf_sha1": "ad30222b6792", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
